public class MergeSort {
    public static void sort(int[] arr, int l, int r) {
        if (l >= r) return;
        int mid = l + (r - l) / 2;
        sort(arr, l, mid);          // sort left half
        sort(arr, mid + 1, r);      // sort right half
        merge(arr, l, mid, r);      // merge sorted halves
    }

    private static void merge(int[] arr, int l, int mid, int r) {
        int[] temp = Arrays.copyOfRange(arr, l, r + 1);
        int i = 0, j = mid - l + 1, k = l;
        while (i <= mid - l && j <= r - l) {
            if (temp[i] <= temp[j]) arr[k++] = temp[i++];
            else                    arr[k++] = temp[j++];
        }
        while (i <= mid - l) arr[k++] = temp[i++];
        while (j <= r - l)   arr[k++] = temp[j++];
    }
}

public class QuickSort {
    public static void sort(int[] arr, int l, int r) {
        if (l >= r) return;
        int p = partition(arr, l, r);
        sort(arr, l, p - 1);
        sort(arr, p + 1, r);
    }

    private static int partition(int[] arr, int l, int r) {
        int pivot = arr[r];   // Lomuto: last element as pivot
        int i = l - 1;        // i = boundary of 'smaller' region
        for (int j = l; j < r; j++) {
            if (arr[j] <= pivot) {
                i++;
                int tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp;
            }
        }
        int tmp = arr[i + 1]; arr[i + 1] = arr[r]; arr[r] = tmp;
        return i + 1;          // pivot's final position
    }
}

public class CountingSort {
    // Sort arr where all values in [min, max]
    public static int[] sort(int[] arr, int min, int max) {
        int[] count = new int[max - min + 1];

        // Step 1: count occurrences
        for (int num : arr)
            count[num - min]++;

        // Step 2: prefix sums (stable sort positions)
        for (int i = 1; i < count.length; i++)
            count[i] += count[i - 1];

        // Step 3: place elements right-to-left (stability)
        int[] output = new int[arr.length];
        for (int i = arr.length - 1; i >= 0; i--)
            output[--count[arr[i] - min]] = arr[i];

        return output;
    }
}

public class HeapSort {
    public static void sort(int[] arr) {
        int n = arr.length;

        // Phase 1: build max-heap bottom-up O(n)
        for (int i = n / 2 - 1; i >= 0; i--)
            heapify(arr, n, i);

        // Phase 2: extract max one by one O(n log n)
        for (int i = n - 1; i > 0; i--) {
            int tmp = arr[0]; arr[0] = arr[i]; arr[i] = tmp;
            heapify(arr, i, 0);
        }
    }

    private static void heapify(int[] arr, int n, int i) {
        int largest = i, l = 2*i+1, r = 2*i+2;
        if (l < n && arr[l] > arr[largest]) largest = l;
        if (r < n && arr[r] > arr[largest]) largest = r;
        if (largest != i) {
            int tmp = arr[i]; arr[i] = arr[largest]; arr[largest] = tmp;
            heapify(arr, n, largest);
        }
    }
}

public class InsertionSort {
    // Sort arr[l..r] — TimSort uses this for small runs
    public static void sort(int[] arr, int l, int r) {
        for (int i = l + 1; i <= r; i++) {
            int key = arr[i];  // card to insert into sorted hand
            int j = i - 1;
            while (j >= l && arr[j] > key) {
                arr[j + 1] = arr[j];  // shift right
                j--;
            }
            arr[j + 1] = key;  // place the card
        }
    }
}

