public class Solution {
    public int maximumGap(int[] nums) {
        if (nums.length < 2) return 0;
        int n = nums.length;
        int min = Integer.MAX_VALUE, max = Integer.MIN_VALUE;
        for (int x : nums) { min = Math.min(min, x); max = Math.max(max, x); }
        if (min == max) return 0;
        int bucketSize = Math.max(1, (max - min) / (n - 1));
        int bucketCount = (max - min) / bucketSize + 1;
        int[] bMin = new int[bucketCount], bMax = new int[bucketCount];
        Arrays.fill(bMin, Integer.MAX_VALUE); Arrays.fill(bMax, Integer.MIN_VALUE);
        for (int x : nums) {
            int b = (x - min) / bucketSize;
            bMin[b] = Math.min(bMin[b], x); bMax[b] = Math.max(bMax[b], x);
        }
        int maxGap = 0, prevMax = min;
        for (int i = 0; i < bucketCount; i++) {
            if (bMin[i] == Integer.MAX_VALUE) continue; // empty bucket
            maxGap = Math.max(maxGap, bMin[i] - prevMax);
            prevMax = bMax[i];
        }
        return maxGap;
    }
}

