public class Solution {
    public List<Integer> pancakeSort(int[] arr) {
        List<Integer> result = new ArrayList<>();
        int n = arr.length;
        for (int size = n; size > 1; size--) {
            // Find position of maximum element in arr[0..size-1]
            int maxIdx = 0;
            for (int i = 1; i < size; i++)
                if (arr[i] > arr[maxIdx]) maxIdx = i;
            if (maxIdx == size - 1) continue; // already in place
            // Flip max to front (if not already there)
            if (maxIdx != 0) {
                result.add(maxIdx + 1);
                reverse(arr, 0, maxIdx);
            }
            // Flip max to its correct position
            result.add(size);
            reverse(arr, 0, size - 1);
        }
        return result;
    }

    private void reverse(int[] arr, int l, int r) {
        while (l < r) { int tmp = arr[l]; arr[l++] = arr[r]; arr[r--] = tmp; }
    }
}
